  phrases: [
    { original: "ሰላም", transliteration: "sälam", translation: "Hello; peace.", usageNote: "Broad and neutral; more elaborate greetings vary with time, relationship, and region." },
    { original: "እንዴት ነህ?", transliteration: "endet näh?", translation: "How are you?", usageNote: "Familiar, addressed to a man. To a woman: እንዴት ነሽ? endet näš?" },
    { original: "እንዴት ነዎት?", transliteration: "endet näwot?", translation: "How are you?", usageNote: "Polite or respectful." },
    { original: "ደህና ነኝ።", transliteration: "dähna näññ", translation: "I'm well." },
    { original: "አመሰግናለሁ።", transliteration: "amäsäggənallähu", translation: "Thank you." },
    { original: "እባክህ", transliteration: "əbbakəh", translation: "Please.", usageNote: "To a man. To a woman use እባክሽ əbbakiš; polite/plural እባክዎ əbbakwo." },
    { original: "ይቅርታ", transliteration: "yəqərta", translation: "Excuse me; sorry." },
    { original: "አልገባኝም።", transliteration: "algäbaññəm", translation: "I don't understand.", literalMeaning: "It did not enter me." },
    { original: "እንደገና ይናገሩ።", transliteration: "əndägäna yənagäru", translation: "Please say it again.", usageNote: "Polite request." },
    { original: "ቀስ ብለው ይናገሩ።", transliteration: "qäs bəläw yənagäru", translation: "Please speak slowly.", usageNote: "Polite; literally asks the person to speak ‘slowly.’" },
    { original: "አማርኛ እየተማርኩ ነው።", transliteration: "amarəñña əyyätämarku näw", translation: "I am learning Amharic." },
    { original: "ይህ ምን ማለት ነው?", transliteration: "yəh mən malät näw?", translation: "What does this mean?" },
    { original: "ስንት ነው?", transliteration: "sənt näw?", translation: "How much is it?; how many is it?", usageNote: "Context supplies the item or quantity." },
    { original: "እሺ", transliteration: "əši", translation: "Okay; all right." },
    { original: "ደህና ሁን", transliteration: "dähna hun", translation: "Goodbye; be well.", usageNote: "Familiar to a man; forms change for a woman, a group, or respectful address." },
    { original: "እንኳን ደህና መጡ", transliteration: "ənkwan dähna mäṭṭu", translation: "Welcome.", usageNote: "Respectful/plural welcome formula." }
  ],
